+  const dividerOutputAnchor = dividerAnchorTowardEndpoint(divider, targetAnchor.side);
+  const orderedLeaves = orderEdgesForDivider(divider, edges, "source");
+
+  return [
+    ...orderedLeaves.map(({ edge, dividerAnchor }) => {
+      const sourceAnchor = edge.layout?.sourceAnchor ?? classAnchorTowardDivider(edge, "source", divider);
+      return {
+        edge,
+        sourceId: edge.sourceId,
+        targetId: divider.id,
+        label: edge.label ?? "",
