+  const dividerCenter = centerOf(divider.layout);
+  return {
+    side: divider.orientation === "vertical"
+      ? (dividerCenter.x >= 0 ? "east" : "west")
+      : (dividerCenter.y >= 0 ? "south" : "north"),
+    ratio: 0.5
+  };
