+  if (anchors.length === 0) {
+    return undefined;
+  }
+
+  const side = anchors[0].side;
+  if (!anchors.every((anchor) => anchor.side === side)) {
+    return anchors[0];
+  }
+
+  return {
+    side,
+    ratio: 0.5
+  };
